<hr id="answer">

<div class="card">
  <button id="record-btn" class="record-btn">🎤 Start Recording</button>
  <div id="status" style="margin-top: 10px; font-size: 14px; color: #64748b;">Ready to practice</div>

  <div id="result-area" class="result-container">
    <div style="font-weight: bold; margin-bottom: 5px; color: #6366f1;">Your Speech:</div>
    <div id="user-speech" class="speech-text">...</div>

    <div style="font-weight: bold; margin-bottom: 5px; margin-top: 15px; color: #a855f7;">AI Feedback:</div>
    <div id="ai-feedback" class="feedback-box">Thinking...</div>
  </div>
</div>

<script>
(function() {
  // === 여기에 본인의 Gemini API Key를 입력하세요 ===
  const API_KEY = "AIzaSyAa44U5SMt0ziSnRoEsILEYxIK1qE_4lo0"; 

  const btn = document.getElementById('record-btn');
  const status = document.getElementById('status');
  const resultArea = document.getElementById('result-area');
  const speechText = document.getElementById('user-speech');
  const feedbackBox = document.getElementById('ai-feedback');

  let recognition;
  let isRecording = false;

  if (!('webkitSpeechRecognition' in window)) {
    status.innerText = "Error: Speech Recognition not supported.";
    btn.style.display = 'none';
    return;
  }

  recognition = new webkitSpeechRecognition();
  recognition.lang = 'en-US';
  recognition.interimResults = false;

  recognition.onresult = (event) => {
    const transcript = event.results[0][0].transcript;
    speechText.innerText = transcript;
    getFeedback(transcript);
  };

  recognition.onerror = (event) => {
    status.innerText = "Error: " + event.error;
    stopUI();
  };

  btn.onclick = () => {
    if (!isRecording) startUI();
    else stopUI();
  };

  function startUI() {
    isRecording = true;
    btn.innerText = "🛑 Stop and Analyze";
    btn.classList.add('active');
    status.innerHTML = '<span class="status-dot"></span>Listening...';
    resultArea.style.display = 'none';
    recognition.start();
  }

  function stopUI() {
    isRecording = false;
    btn.innerText = "🎤 Start Recording";
    btn.classList.remove('active');
    status.innerText = "Analyzing...";
    recognition.stop();
  }

  async function getFeedback(text) {
    resultArea.style.display = 'block';
    feedbackBox.innerText = "Gemini is analyzing your speech...";

    const prompt = `User's spoken answer to "{{문장}}": "${text}". Compare it with the original sentence. Provide 2-3 brief sentences of feedback in Korean regarding pronunciation, grammar, or naturalness, and suggest one natural alternative if needed.`;

    try {
      const resp = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${API_KEY}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ contents: [{ parts: [{ text: prompt }] }] })
      });
      const data = await resp.json();
      const result = data.candidates[0].content.parts[0].text;
      feedbackBox.innerText = result;
      status.innerText = "Analysis Complete";
    } catch (e) {
      feedbackBox.innerText = "Feedback Error: " + e.message;
      status.innerText = "Analysis Failed";
    }
  }
})();
</script>
